-- ملء محتوى عنقود "المرأة المسلمة" (mara-muslima) — خمسة تصنيفات فرعية
-- draft متبقية (السادس ahkam-mara-khassa منشور مسبقًا): مكانة المرأة في
-- الإسلام، اللباس والحجاب، حقوق المرأة، الأمومة، طلب العلم والعمل.
-- كل تصنيف يحصل على درس واحد (lessons + lesson_sections +
-- lesson_citations)، بنفس أسلوب الدفعات السابقة (تعريفي موجز: قسم body
-- + قسم examples).
-- المصادر المعتمدة: المرأة بين الفقه والقانون لمصطفى السباعي (مكانة
-- المرأة)، جلباب المرأة المسلمة في الكتاب والسنة لمحمد ناصر الدين
-- الألباني (اللباس والحجاب)، تحرير المرأة في عصر الرسالة لعبد الحليم
-- أبو شقة (حقوق المرأة)، أحكام النساء لأبي الفرج ابن الجوزي (الأمومة)،
-- فتح الباري بشرح صحيح البخاري لابن حجر العسقلاني (طلب العلم والعمل).
-- ثلاثة أحاديث استُشهد بها، تحقَّقت حرفياً عبر WebSearch قبل الإدراج:
-- «اتقوا الله في النساء فإنكم أخذتموهن بأمان الله...» من خطبة حجة
-- الوداع عن جابر بن عبد الله (رواه مسلم 1218)، «من أحق الناس بحسن
-- صحابتي؟ قال: أمك، ثم أمك، ثم أمك، ثم أبوك» عن أبي هريرة (متفق عليه،
-- البخاري 5971 ومسلم 2548)، «قالت النساء للنبي: غلبنا عليك الرجال
-- فاجعل لنا يومًا من نفسك...» عن أبي سعيد الخدري (البخاري 101، كتاب
-- العلم). لُوحظ أن حديث «النساء شقائق الرجال» درجته حسن فقط عند
-- الألباني (صحيح أبي داود) فاستُبعد لصالح آية قرآنية صريحة لنفس المعنى
-- في تصنيف مكانة المرأة. آيتان تحقَّقتا حرفياً محلياً من
-- artifacts/majalis/public/data/quran عبر numberInSurah: الأحزاب 35
-- (تسوية الأجر بين المسلمين والمسلمات، تصنيف مكانة المرأة)، الأحزاب 59
-- (آية الجلباب، تصنيف اللباس والحجاب).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الخمسة عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) مكانة المرأة في الإسلام
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='c7a2c8d7-2639-4366-8527-8a4edc620c59' AND title='مكانة المرأة في الإسلام: تسوية الأجر بين المسلمين والمسلمات أنموذجًا') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مكانة المرأة في الإسلام: تسوية الأجر بين المسلمين والمسلمات أنموذجًا', 'تعريف موجز بمكانة المرأة في الإسلام، وتسوية الأجر بين المسلمين والمسلمات أنموذجًا لهذه المكانة', 'c7a2c8d7-2639-4366-8527-8a4edc620c59', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'مكانة المرأة أفرد لها السباعي دراسة مقارنة، وتسوية الأجر مع الرجل أصل جامع لها', 'مكانة المرأة في الإسلام موضوع تناوله الشيخ مصطفى السباعي بدراسة مقارنة موسّعة في كتابه "المرأة بين الفقه والقانون"، مبيّنًا أن الإسلام كرّم المرأة وسوّى بينها وبين الرجل في أصل التكليف والثواب والعقاب، مع مراعاة الفروق التي اقتضتها طبيعة كل منهما في بعض الأحكام. ومن أجمع النصوص الدالة على هذه المساواة في الأجر والمكانة الأخروية آية سورة الأحزاب التي عدّدت صفات المؤمنين والمؤمنات معًا وختمتها بوعد جامع بالمغفرة والأجر العظيم لهما دون تفريق.', 1),
    (v_lesson, 'examples', 'آية تسوية الأجر بين المسلمين والمسلمات في سورة الأحزاب', 'قال تعالى: ﴿إِنَّ الْمُسْلِمِينَ وَالْمُسْلِمَاتِ وَالْمُؤْمِنِينَ وَالْمُؤْمِنَاتِ وَالْقَانِتِينَ وَالْقَانِتَاتِ وَالصَّادِقِينَ وَالصَّادِقَاتِ وَالصَّابِرِينَ وَالصَّابِرَاتِ وَالْخَاشِعِينَ وَالْخَاشِعَاتِ وَالْمُتَصَدِّقِينَ وَالْمُتَصَدِّقَاتِ وَالصَّائِمِينَ وَالصَّائِمَاتِ وَالْحَافِظِينَ فُرُوجَهُمْ وَالْحَافِظَاتِ وَالذَّاكِرِينَ اللَّهَ كَثِيرًا وَالذَّاكِرَاتِ أَعَدَّ اللَّهُ لَهُم مَّغْفِرَةً وَأَجْرًا عَظِيمًا﴾ (الأحزاب: 35)، وهي نموذج قرآني صريح لما قرره السباعي من أن الإسلام لم يفرّق بين الرجل والمرأة في أصل الثواب على الأعمال الصالحة، بل عدّد عشر صفات مشتركة وسوّى بينهما فيها جميعًا.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'المرأة بين الفقه والقانون — مصطفى السباعي', 1);
  END IF;

  -- 2) اللباس والحجاب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='7709edb0-45e8-41e0-acfa-91d904942a26' AND title='اللباس والحجاب: آية الجلباب أنموذجًا لأدلة وجوب الحجاب') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('اللباس والحجاب: آية الجلباب أنموذجًا لأدلة وجوب الحجاب', 'تعريف موجز بأحكام اللباس والحجاب في الإسلام، وآية الجلباب أنموذجًا لأدلة وجوبه', '7709edb0-45e8-41e0-acfa-91d904942a26', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'اللباس والحجاب جمع الألباني أدلته في جلباب المرأة المسلمة، وآية الجلباب أصلها', 'أحكام اللباس والحجاب باب من أبواب الفقه يُعنى ببيان ما يجب على المرأة المسلمة من ستر بدنها أمام الرجال الأجانب، وقد جمع الشيخ محمد ناصر الدين الألباني أدلة هذا الباب من الكتاب والسنة في كتابه "جلباب المرأة المسلمة في الكتاب والسنة"، مستقصيًا الآيات والأحاديث الواردة فيه ومناقشًا أقوال الفقهاء حولها. ومن أصرح الآيات الدالة على وجوب الحجاب أمر الله تعالى نبيه أن يوصي أزواجه وبناته ونساء المؤمنين بإدناء الجلابيب عليهن.', 1),
    (v_lesson, 'examples', 'آية الجلباب في سورة الأحزاب وعلّتها', 'قال تعالى: ﴿يَا أَيُّهَا النَّبِيُّ قُل لِّأَزْوَاجِكَ وَبَنَاتِكَ وَنِسَاءِ الْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِن جَلَابِيبِهِنَّ ۚ ذَٰلِكَ أَدْنَىٰ أَن يُعْرَفْنَ فَلَا يُؤْذَيْنَ ۗ وَكَانَ اللَّهُ غَفُورًا رَّحِيمًا﴾ (الأحزاب: 59)، وهذه الآية هي المعتمد الأول عند الألباني في جلباب المرأة المسلمة، إذ ربطت الأمر بإدناء الجلباب بعلّة واضحة هي التعرّف على المرأة المسلمة الحرة العفيفة ودفع الأذى عنها، وهو ما بنى عليه جمهور المفسرين وجوب ستر المرأة بدنها أمام الأجانب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'جلباب المرأة المسلمة في الكتاب والسنة — محمد ناصر الدين الألباني', 1);
  END IF;

  -- 3) حقوق المرأة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='f43e6d2b-8c05-4b41-8e2a-d2579f489c5f' AND title='حقوق المرأة: وصية النبي بالنساء في خطبة حجة الوداع') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('حقوق المرأة: وصية النبي بالنساء في خطبة حجة الوداع', 'تعريف موجز بحقوق المرأة في الإسلام، ووصية النبي صلى الله عليه وسلم بالنساء في خطبة حجة الوداع أنموذجًا', 'f43e6d2b-8c05-4b41-8e2a-d2579f489c5f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'حقوق المرأة وثّقها أبو شقة من نصوص عصر الرسالة، ووصية حجة الوداع ذروتها', 'حقوق المرأة في الإسلام موضوع تتبعه الشيخ عبد الحليم أبو شقة استقصاءً واسعًا في موسوعته "تحرير المرأة في عصر الرسالة"، جامعًا النصوص الصحيحة الدالة على ما كفله الإسلام للمرأة من حقوق في الحياة الزوجية والاجتماعية والمالية. ومن أعظم هذه النصوص وصية النبي صلى الله عليه وسلم بالنساء في خطبته الجامعة في حجة الوداع، التي أعلن فيها أن للنساء على أزواجهن حقوقًا مقابل ما لهم عليهن من حقوق، مؤكدًا أن أخذهن كان بأمان الله وكلمته.', 1),
    (v_lesson, 'examples', 'وصية النبي بالنساء في خطبة حجة الوداع', 'عن جابر بن عبد الله رضي الله عنهما في وصف حجة النبي صلى الله عليه وسلم، أنه قال في خطبته: «اتقوا الله في النساء، فإنكم أخذتموهن بأمان الله، واستحللتم فروجهن بكلمة الله، ولكم عليهن أن لا يوطئن فرشكم أحدًا تكرهونه» (رواه مسلم 1218). وهذا النص هو ما اعتمده أبو شقة في تحرير المرأة في عصر الرسالة أصلاً لبيان أن حقوق المرأة وواجباتها في الإسلام متقابلة متوازنة، وأن أخذها زوجة كان بعهد من الله لا يجوز التفريط فيه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تحرير المرأة في عصر الرسالة — عبد الحليم أبو شقة', 1);
  END IF;

  -- 4) الأمومة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a9bba9fb-21a2-40c4-900c-bc2a04e01ac2' AND title='الأمومة: تقديم الأم ثلاث مرات في وصية النبي بحسن الصحبة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الأمومة: تقديم الأم ثلاث مرات في وصية النبي بحسن الصحبة', 'تعريف موجز بمكانة الأمومة في الإسلام، وتقديم الأم ثلاث مرات في وصية النبي بحسن الصحبة أنموذجًا', 'a9bba9fb-21a2-40c4-900c-bc2a04e01ac2', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'الأمومة أفرد لها ابن الجوزي فصولاً في أحكام النساء، وتكرار ذكر الأم دليل تفضيلها', 'الأمومة في الإسلام مكانة عظيمة تناولها أبو الفرج عبد الرحمن بن الجوزي في كتابه "أحكام النساء" ضمن حديثه عن الحمل والرضاع وحقوق الأم على ولدها، مبيّنًا ما اختصت به الأم من فضل لما تحملته من مشقة الحمل والوضع والإرضاع. ومن أبلغ ما ورد في تقرير هذه المكانة تكرار النبي صلى الله عليه وسلم ذكر الأم ثلاث مرات قبل الأب عند سؤاله عن أحق الناس بحسن الصحبة، دلالة على مضاعفة حقها.', 1),
    (v_lesson, 'examples', 'تقديم الأم ثلاث مرات في حديث حسن الصحبة', 'عن أبي هريرة رضي الله عنه، أن رجلاً جاء إلى رسول الله صلى الله عليه وسلم فقال: يا رسول الله، من أحق الناس بحسن صحابتي؟ قال: «أمك»، قال: ثم من؟ قال: «ثم أمك»، قال: ثم من؟ قال: «ثم أمك»، قال: ثم من؟ قال: «ثم أبوك» (متفق عليه، رواه البخاري 5971 ومسلم 2548). وهذا التكرار الثلاثي للأم قبل ذكر الأب هو ما استدل به ابن الجوزي في أحكام النساء على أن للأم من حق البر والإحسان ضعف ما للأب، لما تحملته من صعاب الحمل والرضاع والتربية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أحكام النساء — أبو الفرج عبد الرحمن بن الجوزي', 1);
  END IF;

  -- 5) طلب العلم والعمل
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='8c213bb0-af9c-4272-8e26-3032b1d826c0' AND title='طلب العلم والعمل: يوم النساء التعليمي عند النبي صلى الله عليه وسلم') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('طلب العلم والعمل: يوم النساء التعليمي عند النبي صلى الله عليه وسلم', 'تعريف موجز بحرص الإسلام على طلب المرأة للعلم، ويوم النساء التعليمي عند النبي صلى الله عليه وسلم أنموذجًا', '8c213bb0-af9c-4272-8e26-3032b1d826c0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'body', 'طلب المرأة للعلم شرح فقهه ابن حجر في فتح الباري، ويومها التعليمي عند النبي أصله', 'حرص الإسلام على تمكين المرأة من طلب العلم موضوع بيّنه الحافظ ابن حجر العسقلاني في كتابه "فتح الباري بشرح صحيح البخاري" عند شرحه لباب "هل يُجعل للنساء يوم على حدة في العلم"، مستنبطًا منه جواز إفراد النساء بمجلس علم خاص إذا دعت الحاجة إلى ذلك. وأصل هذا الباب أن نساء الصحابة رضي الله عنهن طلبن من النبي صلى الله عليه وسلم أن يخصص لهن وقتًا للتعلّم لمّا وجدن الرجال يستأثرون بمجالسته.', 1),
    (v_lesson, 'examples', 'طلب نساء الصحابة يومًا للتعلّم من النبي', 'عن أبي سعيد الخدري رضي الله عنه: «قالت النساء للنبي صلى الله عليه وسلم: غلبنا عليك الرجال، فاجعل لنا يومًا من نفسك، فوعدهن يومًا لقيهن فيه، فوعظهن وأمرهن» (رواه البخاري 101). وهذا الحديث هو الأصل الذي بنى عليه ابن حجر في فتح الباري جواز إفراد النساء بمجلس علم خاص، وهو نموذج تطبيقي مبكر لحرص نساء الصحابة على طلب العلم ومبادرة النبي صلى الله عليه وسلم لتلبية هذا الطلب.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فتح الباري بشرح صحيح البخاري — أحمد بن علي بن حجر العسقلاني', 1);
  END IF;

  -- تحديث حالة التصنيفات الخمسة إلى منشور بعد اكتمال محتواها
  UPDATE categories SET status='published'
  WHERE id IN (
    'c7a2c8d7-2639-4366-8527-8a4edc620c59', '7709edb0-45e8-41e0-acfa-91d904942a26',
    'f43e6d2b-8c05-4b41-8e2a-d2579f489c5f', 'a9bba9fb-21a2-40c4-900c-bc2a04e01ac2',
    '8c213bb0-af9c-4272-8e26-3032b1d826c0'
  );
END $$;
